import React, { useEffect, useState } from "react";
import { api, getToken, clearToken } from "./api";
import Login from "./pages/Login";
import Signup from "./pages/Signup";
import Profile from "./pages/Profile";
import Dashboard from "./pages/Dashboard";
import Recipes from "./pages/Recipes";

export default function App() {
  const [page, setPage] = useState(getToken() ? "dashboard" : "login");
  const [me, setMe] = useState(null);
  const [error, setError] = useState("");

  async function loadMe() {
    try {
      const data = await api.me();
      setMe(data);
    } catch (e) {
      setMe(null);
    }
  }

  useEffect(() => {
    if (getToken()) loadMe();
  }, []);

  function logout() {
    clearToken();
    setMe(null);
    setPage("login");
  }

  const Nav = () => (
    <div className="nav">
      <div className="brand" onClick={() => setPage("dashboard")}>SmartPantry</div>
      {getToken() && (
        <div className="navBtns">
          <button onClick={() => setPage("dashboard")}>Dashboard</button>
          <button onClick={() => setPage("recipes")}>Recipes</button>
          <button onClick={() => setPage("profile")}>Profile</button>
          <button className="danger" onClick={logout}>Logout</button>
        </div>
      )}
    </div>
  );

  return (
    <div className="container">
      <Nav />
      {error && <div className="error">{error}</div>}

      {page === "login" && (
        <Login
          onDone={() => { setError(""); loadMe(); setPage("dashboard"); }}
          goSignup={() => setPage("signup")}
          onError={(m) => setError(m)}
        />
      )}
      {page === "signup" && (
        <Signup
          onDone={() => { setError(""); loadMe(); setPage("dashboard"); }}
          goLogin={() => setPage("login")}
          onError={(m) => setError(m)}
        />
      )}
      {page === "profile" && getToken() && <Profile me={me} refresh={loadMe} onError={(m)=>setError(m)} />}
      {page === "dashboard" && getToken() && <Dashboard onError={(m)=>setError(m)} />}
      {page === "recipes" && getToken() && <Recipes onError={(m)=>setError(m)} />}
    </div>
  );
}
